private boolean toStringEquals(Matcher m, Object arg) {
    if (arg == null || m == null) {
        return false;
    }
    try {
        return StringDescription.toString(m).equals(arg.toString());
    } catch (Exception e) {
        return false;
    }
}

private boolean toStringEquals(Matcher m, Object arg) {
    if (arg == null || m == null) return false;
    return m.getClass().equals(arg.getClass()) && StringDescription.toString(m).equals(arg.toString());
}

private boolean toStringEquals(Matcher m, Object arg) {
    return arg == null ? StringDescription.toString(m) == null : StringDescription.toString(m).equals(arg.toString());
}

